import { Schema, model, Document } from 'mongoose';
import { ObjectId } from 'mongodb';

interface Group extends Document {
  id: ObjectId;
  name: string;
  description: string;
  adminId: ObjectId;
  members: ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const groupSchema = new Schema<Group>({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: Schema.Types.ObjectId, required: true },
  members: [{ type: Schema.Types.ObjectId, ref: 'User' }],
  telegramChatId: { type: String, optional: true },
  createdAt: { type: Date, default: Date.now },
});

const GroupModel = model<Group>('Group', groupSchema);

export { Group, GroupModel };

import { Group, GroupModel } from './group.model';

class GroupRepository {
  async create(groupData: Partial<Group>): Promise<Group> {
    const group = new GroupModel(groupData);
    return group.save();
  }

  async findById(id: string): Promise<Group | null> {
    return GroupModel.findById(id).exec();
  }

  async updateById(id: string, updateData: Partial<Group>): Promise<Group | null> {
    return GroupModel.findByIdAndUpdate(id, updateData, { new: true }).exec();
  }
}

export const groupRepository = new GroupRepository();

import { groupRepository } from './group.repository';
import { Group } from './group.model';

class GroupService {
  async createGroup(groupData: Partial<Group>): Promise<Group> {
    return groupRepository.create(groupData);
  }

  async getGroupById(id: string): Promise<Group | null> {
    return groupRepository.findById(id);
  }

  async linkTelegramGroup(id: string, telegramChatId: string): Promise<Group | null> {
    return groupRepository.updateById(id, { telegramChatId });
  }
}

export const groupService = new GroupService();

import { Request, Response, NextFunction } from 'express';
import { groupService } from './group.service';
import { GroupValidator } from './group.validator';
import { AppError } from '../../utils/app-error';

class GroupController {
  async createGroup(req: Request, res: Response, next: NextFunction) {
    try {
      const validatedData = GroupValidator.createGroup(req.body);
      const group = await groupService.createGroup(validatedData);
      res.status(201).json({ success: true, data: group });
    } catch (error) {
      next(new AppError('CREATE_GROUP_ERROR', error.message));
    }
  }

  async getGroupById(req: Request, res: Response, next: NextFunction) {
    try {
      const { id } = req.params;
      const group = await groupService.getGroupById(id);
      if (!group) {
        throw new AppError('GROUP_NOT_FOUND', 'Group not found');
      }
      res.json({ success: true, data: group });
    } catch (error) {
      next(new AppError('GET_GROUP_ERROR', error.message));
    }
  }

  async linkTelegramGroup(req: Request, res: Response, next: NextFunction) {
    try {
      const { id } = req.params;
      const { telegramChatId } = req.body;
      const group = await groupService.linkTelegramGroup(id, telegramChatId);
      if (!group) {
        throw new AppError('GROUP_NOT_FOUND', 'Group not found');
      }
      res.json({ success: true, data: group });
    } catch (error) {
      next(new AppError('LINK_TELEGRAM_ERROR', error.message));
    }
  }
}

export const groupController = new GroupController();

import { z } from 'zod';

const createGroupSchema = z.object({
  name: z.string().nonempty(),
  description: z.string().nonempty(),
  adminId: z.string().nonempty().uuid(),
});

class GroupValidator {
  static createGroup(data: any) {
    return createGroupSchema.parse(data);
  }
}

export { GroupValidator };
